query UserGroupMyAccess {
  fetchUserGroups(filterByCurrentUser: true, status: "Granted") {
    id
    name
    description
    dimensions {
      id
      name
      rank
      __typename
    }
    memberships(forCurrentUser: true, status: "Granted") {
      id
      user {
        id
        email
        displayName
        __typename
      }
      role {
        id
        name
        hierarchyLevel
        canManage
        __typename
      }
      membershipDetails {
        dimId
        value
        valueDescription
        id
        __typename
      }
      __typename
    }
    __typename
  }
}

query MyQuery {
  fetchPaginatedDimensions(
    paginationFilters: {limit: 1000, page: 1}
    dimensionIds: [1]
  ) {
    limit
    page
    totalRecords
    dimensions {
      dimensionId
      name
      description
      values(searchText: "", version: 1) {
        valueId
        name
        aliases {
          aliasName
          __typename
        }
        __typename
      }
      __typename
    }
    __typename
  }
}

query MyQuery {
  fetchPaginatedDimensions(
    paginationFilters: {limit: 1000, page: 1}
    dimensionIds: [1]
  ) {
    limit
    page
    totalRecords
    dimensions {
      dimensionId
      name
      description
      values(
        searchText: ""
        version: 1
        relationshipFilter: {intersetOperations: [], sets: [{pairs: [{dimId: 2, value: "cdbc70db-d904-4cd7-a9f5-afa46376552e"}], operation: OR}]}
      ) {
        valueId
        name
        aliases {
          aliasName
          __typename
        }
        __typename
      }
      __typename
    }
    __typename
  }
}

