query FetchBatchUserMapping {
  fetch_batch_user_mapping(input: {batch_id: "TODO_BATCH_ID", po_number: "TODO_PO", po_itm_number: "TODO_PO_ITEM"}) {
    batch_id
    po_number
    po_itm_number
    assign_user_ids
    users {
      id
      email
      displayName
    }
  }
}

query MyQuery {
  fetchApplications {
    applicationId
    name
    description
    type
    url
    defaultOrder
    version
    hasGlobalSearch
    associatedDimensions {
      dimensionId
      displaySequenceNumber
      requiredFlag
      __typename
    }
    associatedUserPreferences(forCurrentUser: true) {
      category
      sequenceNumber
      __typename
    }
    __typename
  }
}

query FetchUserNotifications {
  fetchPaginatedNotifications(
    paginatedNotificationInput: {sortBy: SNOOZE_UNTIL_TIMESTAMP, sortOrder: DESC, forCurrentUser: true, first: 200}
  ) {
    notifications {
      eventId
      userId
      isRead
      isArchived
      snoozeUntilTimestamp
      eventDetails {
        eventId
        definitionId
        header
        text
        priorityName
        generatedAt
        eventJson
        metaData {
          eventId
          key
          value
          isRequiredInPush
          isRequiredInApp
          isRequiredInEmail
          sequenceNum
          __typename
        }
        __typename
      }
      __typename
    }
    paginationInfo {
      startCursor
      endCursor
      hasNextPage
      hasPreviousPage
      __typename
    }
    __typename
  }
}
